import React from 'react';

const Careers = () => {
  return (
    <div className="pt-24 min-h-screen bg-white">
      <div className="max-w-7xl mx-auto px-4 py-16">
        <div className="bg-blue-50 rounded-3xl p-10 text-center">
          <h1 className="text-4xl font-bold text-gray-900 mb-4">Start Your Career With Us</h1>
          <p className="text-gray-600 mb-8">We are always looking for passionate people to join our global team.</p>
          <button className="bg-blue-600 text-white px-10 py-4 rounded-full font-bold hover:bg-blue-700">
            View Current Openings
          </button>
        </div>
      </div>
    </div>
  );
};

export default Careers;
